const builtTests = entryPoints.map((entry) => path.join(outdir, `${path.basename(entry).replace(/\.(tsx|ts)$/, "")}.js`));
const result = spawnSync(process.execPath, ["--test", ...builtTests], {
  cwd: projectRoot,
  stdio: "inherit"
});

process.exit(result.status ?? 1);

